const $form = document.querySelector('#form');

$form.addEventListener('submit', handlesubmit);

async function handlesubmit(event) {
    event.preventDefault();

    const form = new FormData(this);
    const response = await fetch(this.action, {
        method: this.method,
        body: form,
        headers: {
            'accept': 'application/json'
        }
    });

    if (response.ok) {
        $form.reset();

        const mensajeExito = document.createElement('section');
        mensajeExito.textContent = "Gracias por completar el formulario, estaré contactandote lo más pronto posible.";
        mensajeExito.classList.add('enviado'); 

        const ubicacionAqui = document.querySelector('#mensaje-exito');

        ubicacionAqui.insertAdjacentElement('beforebegin', mensajeExito);

        setTimeout(() => {
            mensajeExito.style.display = 'none';
        }, 5000);
    }
}

function downloadCV() {
    var language = document.getElementById("language").value;
    var filePath;

    if (language === "es") {
        filePath = "cv/español/Daniel Cos CV.pdf";
    } else if (language === "en") {
        filePath = "cv/ingles/Daniel Cos CV.pdf";
    }

    var downloadLink = document.createElement("a");
    downloadLink.setAttribute("download", "Daniel Cos CV " + language + ".pdf");
    downloadLink.href = filePath;

    downloadLink.click();
}

// =========================
// LOADER INTELIGENTE
// =========================

const yaCargo = sessionStorage.getItem("loaderMostrado");

if (!yaCargo) {

    document.body.classList.add("loading");

    window.addEventListener("load", () => {

        const bar = document.getElementById("loader-bar");
        const percent = document.getElementById("loader-percent");
        const text = document.getElementById("loader-text");
        const loader = document.getElementById("loader");
        const dots = document.getElementById("loader-dots");

        let progress = 0;

        const interval = setInterval(() => {
            progress++;

            bar.style.width = progress + "%";
            percent.textContent = progress + "%";

            dots.textContent = ".".repeat((progress % 3) + 1);

            if (progress >= 100) {
                clearInterval(interval);

                text.textContent = "Listo";

                setTimeout(() => {
                    loader.style.opacity = "0";
                    loader.style.transition = "opacity 0.5s ease";

                    setTimeout(() => {
                        loader.style.display = "none";
                        document.body.classList.remove("loading");

                        // 🔥 MARCAR COMO MOSTRADO
                        sessionStorage.setItem("loaderMostrado", "true");

                    }, 500);

                }, 500);
            }

        }, 20);
    });

} else {
    // 🔥 SI YA SE MOSTRÓ → ocultarlo instantáneamente
    const loader = document.getElementById("loader");
    if (loader) loader.style.display = "none";
}